#include <iostream>
#include <vector>

using namespace std;

// Function to calculate and return nth Fibonacci number using Dynamic Programming 
int fibonacci(int n) 
{ 
    // Create an array to store Fibonacci numbers 
    vector<int> f(n + 1); 

    // 0th and 1st number of the series are 0 and 1 
    f[0] = 0; 
    f[1] = 1; 

    // Add the previous 2 numbers in the series and store it 
    for (int i = 2; i <= n; i++) 
        f[i] = f[i - 1] + f[i - 2]; 

    return f[n]; 
} 

int main() 
{ 
    int n;

    // Get the nth number
	cout << "Enter the nth number: ";
	cin >> n;

	// Display the result 
    cout << "The nth Fibonacci number is: " << fibonacci(n); 

    return 0; 
}

function binarySearch(arr, target) {
  // Set initial values for min and max
  let min = 0; 
  let max = arr.length - 1;

  // Set initial midpoint
  let mid = Math.floor((min + max) / 2);

  // While min is less than or equal to max
  while(min <= max) {
    // If the element at mid is equal to the target
    if(arr[mid] === target) {
      // Return mid
      return mid;
    }
    // Else if the element at mid is less than the target
    else if(arr[mid] < target) {
      // Set min to mid + 1
      min = mid + 1;
    }
    // Else if the element at mid is greater than the target
    else if(arr[mid] > target) {
      // Set max to mid - 1
      max = mid - 1;
    }

    // Recalculate mid
    mid = Math.floor((min + max) / 2);
  }

  // If the target is not found, return -1
  return -1;
}
